digraph G {
    rankdir=LR;
    node [shape=box, style=filled, fillcolor=lightblue];

    subgraph cluster_CPU {
        label="Central Processing Unit";
        style=filled;
        fillcolor=lightyellow;

        Control_Circuits [label="Control Circuits"];

        subgraph cluster_Registers {
            label="Registers";
            style=filled;
            fillcolor=lightgreen;

            AC [label="AC (Accumulator)"];
            MQ [label="MQ (Multiplier-Quotient)"];
            MBR [label="MBR (Memory Buffer Register)"];
            IBR [label="IBR (Instruction Buffer Register)"];
            PC [label="PC (Program Counter)"];
            MAR [label="MAR (Memory Address Register)"];
            IR [label="IR (Instruction Register)"];
        }
    }

    Main_Memory [label="Main Memory", shape=cylinder, fillcolor=lightpink];
    Input_Equipment [label="Input Equipment", shape=ellipse, fillcolor=lightgray];
    Output_Equipment [label="Output Equipment", shape=ellipse, fillcolor=lightgray];

    Control_Circuits -> Registers [dir=both];
    MBR -> Main_Memory [dir=both, label="data"];
    MAR -> Main_Memory [dir=forward, label="address"];
    Input_Equipment -> MBR [dir=forward];
    MBR -> Output_Equipment [dir=forward];
}

