digraph G {
    rankdir=LR;
    node [shape=box, style=filled, fillcolor=lightgray];
    subgraph cluster_CPU {
        label="Central Processing Unit (CPU)";
        style=filled;
        fillcolor=lightblue;
        subgraph cluster_CU {
            label="Control Unit (CU)";
            PC [label="Program Counter (PC)"];
            IR [label="Instruction Register (IR)"];
            PC -> IR [dir=both];
        }
        ALU [label="Arithmetic Logic Unit (ALU)"];
        AC [label="Accumulator (AC)"];
        MQ [label="Multiplier-Quotient (MQ)"];
        MAR [label="Memory Address Register (MAR)"];
        MBR [label="Memory Buffer Register (MBR)"];
        ALU -> AC [dir=both];
        ALU -> MQ [dir=forward];
        CU -> MAR [style=dashed];
        CU -> MBR [style=dashed];
        CU -> ALU [style=dashed];
        CU -> PC [style=dashed];
        CU -> I_O [style=dashed];
        PC -> MAR [dir=forward];
        IR -> CU [label="opcode", dir=forward];
        IR -> MAR [label="address field", dir=forward];
    }
    Memory [label="Main Memory (M)\nMEMORY (Instructions & Data)\nAddress | Word (40 bits)", shape=box, fillcolor=lightyellow];
    I_O [label="Input/Output Equipment", shape=box, fillcolor=lightgreen];
    MAR -> Memory [label="Address Bus", dir=forward];
    MBR -> Memory [label="Data Bus", dir=both];
    Memory -> MBR [label="Instruction Fetch", dir=forward];
    MBR -> IR [dir=forward];
    MBR -> I_O [dir=both];
}

