digraph G {
  rankdir=LR;
  node [shape=box, style=filled, fillcolor=lightgray];
  edge [arrowhead=normal];

  subgraph cluster_cpu {
    label="Central Processing Unit (CPU)";
    style=filled;
    fillcolor=lightblue;
    ControlUnit [label="Control Unit"];
    ALU [label="Arithmetic Logic Unit (ALU)"];
    Registers [label="Registers"];
    PC [label="Program Counter (PC)"];
    ControlUnit -> ALU [style=invis];
    ControlUnit -> Registers [style=invis];
    ControlUnit -> PC [style=invis];
  }

  InstructionMemory [label="Instruction Memory (ROM/RAM)", shape=box, style=filled, fillcolor=lightyellow];
  DataMemory [label="Data Memory (RAM)", shape=box, style=filled, fillcolor=lightyellow];

  subgraph cluster_instruction_bus {
    label="Instruction Bus";
    style=dashed;
    fillcolor=white;
    AddressLines_I [label="Address Lines", shape=plaintext];
    DataLines_I [label="Data Lines", shape=plaintext];
    ControlLines_I [label="Control Lines", shape=plaintext];
    AddressLines_I -> DataLines_I [style=invis];
    DataLines_I -> ControlLines_I [style=invis];
  }

  subgraph cluster_data_bus {
    label="Data Bus";
    style=dashed;
    fillcolor=white;
    AddressLines_D [label="Address Lines", shape=plaintext];
    DataLines_D [label="Data Lines", shape=plaintext];
    ControlLines_D [label="Control Lines", shape=plaintext];
    AddressLines_D -> DataLines_D [style=invis];
    DataLines_D -> ControlLines_D [style=invis];
  }

  ControlUnit -> ControlLines_I [label="Control Signals", dir=both];
  ControlUnit -> ControlLines_D [label="Control Signals", dir=both];
  PC -> AddressLines_I [label="Instruction Address"];
  ALU -> AddressLines_D [label="Data Address"];
  AddressLines_I -> InstructionMemory;
  InstructionMemory -> DataLines_I [label="Instruction Code"];
  DataLines_I -> ControlUnit;
  AddressLines_D -> DataMemory;
  DataMemory -> DataLines_D [label="Data Transfer", dir=both];
  DataLines_D -> Registers [label="Data to/from Registers", dir=both];
  DataLines_D -> ALU [label="Data to/from ALU", dir=both];
  DataLines_I -> ControlUnit [label="Instruction to Control Unit"];
}
